19	bool OpTrait::cuda_tile::impl::verifyLoadStoreType(Type dstType, Type srcType) {
20	  if (!isPointerLike(srcType) || !isa<TileType>(dstType))
21	    return false;
22	
23	  auto dstTensorType = cast<TileType>(dstType);
24	  auto srcTensorType = cast<TileType>(srcType);
25	  auto srcPointerType = cast<PointerType>(srcTensorType.getElementType());
26	
27	  return srcTensorType.getShape() == dstTensorType.getShape() &&
28	         srcPointerType.getPointeeType() == dstTensorType.getElementType();
